+    public IActionResult GenerateTraditionalApp()
+    {
+        var appData=new LeviathansDTO();
+        appData.LeviathanDescription = "This is a collection of all the data needed to generate a traditional application in CATS. It includes lists of all Controllers, Models, DTOs, and Database Tables. This data can be used to create a new application with standard CRUD operations based on the existing structure of CATS.";
+             //Controllers = ControllersList,
+             //Models = allModels.Select(m => m.Name).ToList(),
+             //DTOs = Assembly.GetExecutingAssembly().GetTypes().Where(t => t.IsClass && t.Name.EndsWith("DTO")).Select(t => t.Name).ToList(),
+             //Tables = allTables
+        // Gather all Model Data needed to generate a traditional
+        var allControllers = ControllersList;
+        var allModels = _db.GetType().GetProperties();
+        var theModels = new List<ModelDTO>();
+        foreach (var model in allModels)
+        {
+            var modelType = model.PropertyType.GetGenericArguments().FirstOrDefault();
+            if (modelType != null)
+            {
+                var mDTO = new ModelDTO();
+                mDTO.Name = model.Name;
+                mDTO.Properties = modelType.GetProperties().Select(prop => new PropertyInfoDTO
+                {
+                    name = prop.Name,
+                    type = prop.PropertyType.FullName
+                }).ToList();
+                mDTO.type = modelType.FullName;
+                theModels.Add(mDTO);
+            }
+        }
+
+        var allDTOs = Assembly.GetExecutingAssembly().GetTypes()
+                        .Where(t => t.IsClass && t.Name.EndsWith("DTO")).Select(t => t.Name).ToList();
+
+        var allTables = new List<string>();
+
+        var conn = db.Database.GetDbConnection();
+        var wasOpen = conn.State == ConnectionState.Open;
+        try
+        {
+            if (!wasOpen)
+            {
+                db.Database.OpenConnection();
+            }
+
+            allTables = conn.GetSchema("Tables").Rows
+                .Cast<DataRow>()
+                .Select(r => r["TABLE_NAME"].ToString())
+                .ToList();
+        }
+        finally
+        {
+            if (!wasOpen)
+            {
+                db.Database.CloseConnection();
+            }
+        }
+
+        var leviathan = new
+        {
+            Controllers = allControllers,
+            Models = allModels,
+            DTOs = allDTOs,
+            Tables = allTables
+        };
+        return View(leviathan);
+    }
+
