+    let appTradGen={n:"button",i:"konamiTradApp",c:"btn btn-dark border-2 border-aqua mb-n1 ms-0 p-2",t:"Generate Traditional App"};
+    innerKon.b.push(appTradGen);
+    kon.b.push(innerKon);
+    normyDiv.insertAdjacentHTML("afterEnd",jmlToHtml(kon));
+    let tradAppBtn=document.querySelector("#konamiTradApp");
